+      } else {
+        output.writeln();
+
+        // Connection info
+        output.writeln(output.highlight('Connection:'));
+        output.printTable({
+          columns: [
+            { key: 'property', header: 'Property', width: 20 },
+            { key: 'value', header: 'Value', width: 40 },
