+  let batch: Array<{ id: string; vector: number[]; metadata?: Record<string, unknown> }> = [];
+  let batchCount = 0;
+  let totalWritten = 0;
+
+  const stream = new Writable({
+    objectMode: true,
+
+    async write(chunk, encoding, callback) {
+      batch.push(chunk);
+
+      if (batch.length >= batchSize) {
