+          await insertFn(batch);
+          totalWritten += batch.length;
+          batchCount++;
+          batch = [];
+          callback();
+        } catch (error) {
+          callback(error as Error);
+        }
+      } else {
+        callback();
+      }
+    },
+
+    async final(callback) {
+      if (batch.length > 0) {
