+  return {
+    iterations,
+    totalMs: times.reduce((sum, t) => sum + t, 0),
+    avgMs: times.reduce((sum, t) => sum + t, 0) / iterations,
+    minMs: times[0],
+    maxMs: times[times.length - 1],
