+  for (let i = 1; i < results.length; i++) {
+    if (
+      results[i].distance !== undefined &&
+      results[i - 1].distance !== undefined &&
+      results[i].distance! < results[i - 1].distance!
+    ) {
+      throw new Error(
+        `Results not sorted by distance: ${results[i - 1].distance} < ${results[i].distance}`
