+    return codes;
+  }
+
+  decode(codes: Uint8Array): number[] {
+    const result: number[] = [];
+
+    for (let m = 0; m < this.numSubvectors; m++) {
+      const centroid = this.codebooks[m][codes[m]];
+      result.push(...centroid);
+    }
