+      totalErrors: this.stats.totalErrors,
+      durationMs: this.getElapsedMs(),
+      throughput: this.getThroughput(),
+      avgBatchDuration: this.getAverageBatchDuration(),
+      peakMemoryMB: Math.max(...this.stats.memoryUsage) / (1024 * 1024),
