+    try {
+      const result = await operation();
+      success = true;
+      return result;
+    } catch (error) {
+      throw error;
+    } finally {
+      const duration = performance.now() - startTime;
+      context.operations.push({
+        type: operationType,
+        target,
+        success,
+        duration,
+      });
+    }
+  }
