+  }
+
+  private async registerResolvedPlugin(
+    plugin: IPlugin,
+    entry: PluginCollectionEntry
+  ): Promise<void> {
+    const settings = this.pluginSettings.get(plugin.metadata.name);
+
+    const config: Partial<PluginConfig> = {
+      enabled: true,
+      settings: settings ?? {},
+    };
+
+    await this.registry.register(plugin, config);
+  }
+}
